
/* Charts */
const chartData={revenue:{D:{labels:['Mon','Tue','Wed','Thu','Fri','Sat','Sun'],values:[820,1240,680,1580,1100,2200,960]},M:{labels:['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'],values:[7840,8900,10160,11800,9400,10800,8600,9900,9200,11200,13400,15800]},Y:{labels:['2021','2022','2023','2024','2025','2026'],values:[84000,112000,148000,196000,264000,128000]}},pieces:{D:{labels:['Mon','Tue','Wed','Thu','Fri','Sat','Sun'],values:[28,44,19,61,38,82,34]},M:{labels:['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'],values:[290,340,410,520,380,445,310,398,360,480,580,680]},Y:{labels:['2021','2022','2023','2024','2025','2026'],values:[2800,4200,6100,8400,11600,5400]}}};
const analyticsData={D:{ok:38,fail:4},M:{ok:1042,fail:76},Y:{ok:9800,fail:720}};
let currentMetric='revenue',currentPeriod='D',mainChart,ringChart;
function buildMainChart(){if(mainChart)mainChart.destroy();const d=chartData[currentMetric][currentPeriod];mainChart=new Chart(document.getElementById('mainChart'),{type:'bar',data:{labels:d.labels,datasets:[{data:d.values,backgroundColor:'#2dbd8f',borderRadius:5,hoverBackgroundColor:'#3dcfa0'}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false},tooltip:{callbacks:{label:ctx=>currentMetric==='revenue'?' £'+ctx.raw.toLocaleString():' '+ctx.raw+' pcs'}}},scales:{x:{grid:{display:false},ticks:{font:{size:10},color:'#5e5c58',maxRotation:0}},y:{grid:{color:'rgba(255,255,255,0.04)'},ticks:{font:{size:10},color:'#5e5c58',callback:v=>currentMetric==='revenue'?'£'+(v>=1000?(v/1000).toFixed(0)+'k':v):v}}}}});}
function buildRingChart(){const a=analyticsData[currentPeriod];const total=a.ok+a.fail;const okPct=Math.round((a.ok/total)*100);const failPct=100-okPct;document.getElementById('ring-pct').textContent=okPct+'%';document.getElementById('leg-ok').textContent=a.ok.toLocaleString();document.getElementById('leg-fail').textContent=a.fail.toLocaleString();if(ringChart)ringChart.destroy();ringChart=new Chart(document.getElementById('ringChart'),{type:'doughnut',data:{datasets:[{data:[okPct,failPct],backgroundColor:['#2dbd8f','#6b2424'],borderWidth:0,hoverOffset:0}]},options:{cutout:'72%',responsive:false,plugins:{legend:{display:false},tooltip:{enabled:false}},animation:{duration:500}}});}
function switchMetric(m,el){currentMetric=m;document.querySelectorAll('.ctoggle').forEach(b=>b.classList.remove('active'));el.classList.add('active');buildMainChart();}
function switchPeriod(p,el){currentPeriod=p;document.querySelectorAll('.ptab').forEach(b=>b.classList.remove('active'));el.classList.add('active');buildMainChart();buildRingChart();}

/* Nav */
function goTo(pageId){document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));document.getElementById(pageId).classList.add('active');const navMap={'pg-home':'nav-home','pg-products':'nav-products','pg-orders':'nav-orders'};document.querySelectorAll('.nav-item').forEach(n=>{n.classList.remove('active');n.querySelectorAll('svg').forEach(s=>s.setAttribute('stroke','var(--color-text-secondary)'));n.querySelector('.nav-label').style.color='';});if(navMap[pageId]){const nav=document.getElementById(navMap[pageId]);nav.classList.add('active');nav.querySelectorAll('svg').forEach(s=>s.setAttribute('stroke','#2dbd8f'));nav.querySelector('.nav-label').style.color='#2dbd8f';}if(pageId==='pg-products'){renderProducts();renderPhotoGrid();}if(pageId==='pg-orders'){updateSummary();applyFilters();}if(pageId==='pg-notif')document.getElementById('notif-dot').style.display='none';}
function openMenu(){document.getElementById('menu-overlay').classList.add('open');}
function closeMenu(){document.getElementById('menu-overlay').classList.remove('open');}
function openPayout(){document.getElementById('payout-overlay').classList.add('open');}
function closePayout(){document.getElementById('payout-overlay').classList.remove('open');}

