function setFilter(f,el){activeFilter=f;document.querySelectorAll('.fchip').forEach(c=>c.classList.remove('active'));el.classList.add('active');applyFilters();}
function applyFilters(){const q=(document.getElementById('search-input')?document.getElementById('search-input').value||'':'').toLowerCase();const list=orders.filter(o=>{const mf=activeFilter==='all'||o.status===activeFilter;const mq=!q||o.id.toLowerCase().includes(q)||o.customerName.toLowerCase().includes(q)||o.city.toLowerCase().includes(q)||o.product.toLowerCase().includes(q);return mf&&mq;});renderOrders(list);}
function updateSummary(){const nc=orders.filter(o=>o.status==='new').length;const st=document.getElementById('s-total');const sn=document.getElementById('s-new-sub');const ss=document.getElementById('s-ship');const sd=document.getElementById('s-done');if(st)st.textContent=orders.length;if(sn)sn.textContent=nc+' new';if(ss)ss.textContent=orders.filter(o=>o.status==='confirmed'||o.status==='shipped').length;if(sd)sd.textContent=orders.filter(o=>o.status==='delivered').length;const banner=document.getElementById('new-banner');if(banner)banner.style.display=nc>0?'flex':'none';const bt=document.getElementById('new-banner-text');if(bt)bt.textContent=nc+' new';const fcNew=document.getElementById('fc-new');if(fcNew)fcNew.innerHTML=nc>0?`New (${nc}) <span style="display:inline-block;width:5px;height:5px;border-radius:50%;background:#E24B4A;margin-left:3px;vertical-align:middle;animation:blink 1.5s infinite"></span>`:'New';}
function advance(id,ns){const o=orders.find(x=>x.id===id);if(o){o.status=ns;updateSummary();applyFilters();}}
function buildStepper(s){if(s==='failed')return`<div style="font-size:12px;color:#e07070;font-weight:500;margin-bottom:12px">Order failed</div>`;const si=ST[s]?.step??0;let h='<div class="stepper">';STEPS.forEach((step,i)=>{const d=i<si,c=i===si;if(i>0)h+=`<div class="stp-line ${d?'done':''}"></div>`;h+=`<div class="stp"><div class="stp-dot ${d?'done':c?'cur':''}"></div><div class="stp-lbl ${d?'done':c?'cur':''}">${step}</div></div>`;});return h+'</div>';}
function buildActions(o){if(o.status==='delivered'||o.status==='failed')return`<div class="action-row"><button class="act a-lock" disabled>${o.status==='delivered'?'✓ Delivered':'Failed'}</button></div>`;let b='';if(o.status==='new')b+=`<button class="act a-confirm" onclick="event.stopPropagation();advance('${o.id}','confirmed')">Confirm order</button>`;if(o.status==='confirmed')b+=`<button class="act a-ship" onclick="event.stopPropagation();advance('${o.id}','shipped')">Mark shipped</button>`;if(o.status==='shipped')b+=`<button class="act a-deliver" onclick="event.stopPropagation();advance('${o.id}','delivered')">Mark delivered</button>`;b+=`<button class="act a-fail" onclick="event.stopPropagation();advance('${o.id}','failed')">Failed</button>`;return`<div class="action-row">${b}</div>`;}
function renderOrders(list){const el=document.getElementById('orders-list');if(!el)return;if(!list.length){el.innerHTML='<div class="empty-state">No orders found.</div>';return;}el.innerHTML=list.map(o=>{const st=ST[o.status]||ST.new;const isExp=expandedId===o.id;const isNew=o.status==='new';const ph=o.photos&&o.photos.length;const photoEl=`<div class="prod-photo">${ph&&o.photos[0].startsWith('data:')?`<img src="${o.photos[0]}"/>`:ph?o.photos[0]:o.productEmoji}</div>`;const strip=ph&&isExp?`<div class="photo-strip-o">${o.photos.map(p=>p.startsWith('data:')?`<div class="s-photo"><img src="${p}"/></div>`:`<div class="s-photo">${p}</div>`).join('')}</div>`:'';const rightSide=`<div class="oc-amt">${fmt(o.total,o.sym)}</div><div class="status-dot-row"><div class="status-dot" style="background:${st.dot};opacity:0.7"></div><span class="status-text">${st.label}</span></div>`;const newTag=isNew&&!isExp?`<div class="new-tag"><div class="nd"></div></div>`:'';const payLabel=o.paymentType==='upfront'?'Upfront fee paid':'Full payment received';const codBanner=o.paymentType==='upfront'?`<div style="display:flex;align-items:center;gap:10px;background:#3a2a10;border-radius:12px;padding:11px 14px;margin-bottom:12px;"><div style="width:32px;height:32px;border-radius:8px;background:#5a3e18;display:flex;align-items:center;justify-content:center;flex-shrink:0;"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#c9923a" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17 9V7a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2m2 4h10a2 2 0 002-2v-6a2 2 0 00-2-2H9a2 2 0 00-2 2v6a2 2 0 002 2z"/></svg></div><div><div style="font-size:13px;font-weight:500;color:#c9923a;">Cash on delivery</div><div style="font-size:11px;color:#9e7040;margin-top:1px;">Customer pays remaining balance on arrival</div></div></div>`:'';const inner=isExp?`<div class="oc-inner open">${strip}<div class="ipad">${buildStepper(o.status)}<div class="appr-note"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>Approved by marketer · ${o.date}</div><div class="pay-badge"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>${payLabel} · ${fmt(o.paymentAmount,o.sym)} · ${o.paymentDate}</div>${codBanner}<div class="st">Customer &amp; delivery</div><div class="db"><div class="dr"><span class="dl">Name</span><span class="dv">${o.customerName}</span></div><div class="dr"><span class="dl">Phone</span><span class="dv">${o.customerPhone}</span></div>${o.customerWhatsapp?`<div class="dr"><span class="dl">WhatsApp</span><span class="dv">${o.customerWhatsapp}</span></div>`:''}<div class="dr"><span class="dl">Address</span><span class="dv">${o.address}</span></div><div class="dr"><span class="dl">City</span><span class="dv">${o.city}, ${o.country}</span></div></div><div class="st">Order</div><div class="db"><div class="dr"><span class="dl">Order ID</span><span class="dv mono">${o.id}</span></div><div class="dr"><span class="dl">Source</span><span class="dv">${o.source==='manual'?'Manual (marketer)':'Affiliate link'}</span></div><div class="dr"><span class="dl">Product</span><span class="dv">${o.product}</span></div><div class="dr"><span class="dl">Code</span><span class="dv mono">${o.productCode}</span></div>${o.size?`<div class="dr"><span class="dl">Size</span><span class="dv">${o.size}</span></div>`:''}${o.color?`<div class="dr"><span class="dl">Colour</span><span class="dv">${o.color}</span></div>`:''}<div class="dr"><span class="dl">Quantity</span><span class="dv">${o.qty}</span></div></div><div class="st">Financials</div><div class="fin-grid"><div class="fi"><div class="fi-l">Product price</div><div class="fi-v">${fmt(o.price,o.sym)}</div></div><div class="fi"><div class="fi-l">Order total</div><div class="fi-v">${fmt(o.total,o.sym)}</div></div><div class="fi"><div class="fi-l">Shipping</div><div class="fi-v">${fmt(o.shipping,o.sym)}</div></div><div class="fi"><div class="fi-l">Delivery</div><div class="fi-v">${fmt(o.delivery,o.sym)}</div></div><div class="fi"><div class="fi-l">Marketer comm.</div><div class="fi-v" style="color:#e07070">−${fmt(o.commission,o.sym)}</div></div><div class="fi"><div class="fi-l">Platform fee</div><div class="fi-v" style="color:#e07070">−${fmt(o.platformFee,o.sym)}</div></div></div>${o.notes?`<div class="st">Notes</div><div class="notes-box">${o.notes}</div>`:''}${buildActions(o)}</div></div>`:`<div class="oc-inner"></div>`;return`<div class="oc ${isNew?'is-new':''} ${isExp?'expanded':''}" onclick="toggle('${o.id}')">${newTag}<div class="oc-outer">${photoEl}<div class="oc-left"><div class="oc-cust">${o.customerName}</div><div class="oc-sub">${o.product} · ${o.city}, ${o.country}</div></div><div class="oc-right">${rightSide}</div><svg class="chevron ${isExp?'open':''}" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><polyline points="9 18 15 12 9 6"/></svg></div>${inner}</div>`;}).join('');}
function toggle(id){expandedId=expandedId===id?null:id;applyFilters();}

buildMainChart();buildRingChart();

